script:
frappe.ui.form.on('Lead', {
    refresh: function(frm) {
            setup_vendor_filters(frm);
                },

                        custom_territory_display: function(frm) {
                                setup_vendor_filters(frm);
                                    },

                                            territory: function(frm) {
                                                    if (!frm.doc.custom_territory_display) {
                                                                setup_vendor_filters(frm);
                                                                        }
                                                                            }
                                                                            });

                                                                            function setup_vendor_filters(frm) {
                                                                                const territory = frm.doc.custom_territory_display || frm.doc.territory;

                                                                                        if (!territory) {
                                                                                                return;
                                                                                                    }

                                                                                                            // Filter vendor_assign field
                                                                                                                frm.set_query("vendor_assign", function () {
                                                                                                                        return {
                                                                                                                                    query: "solar_erp.solar_erp.api.lead_vendor.get_technical_vendors",
                                                                                                                                                filters: {
                                                                                                                                                                territory: territory
                                                                                                                                                                            }
                                                                                                                                                                                    };
                                                                                                                                                                                        });

                                                                                                                                                                                                // Filter meter_execution_vendor field
                                                                                                                                                                                                    frm.set_query("meter_execution_vendor", function () {
                                                                                                                                                                                                            return {
                                                                                                                                                                                                                        query: "solar_erp.solar_erp.api.lead_vendor.get_meter_vendors",
                                                                                                                                                                                                                                    filters: {
                                                                                                                                                                                                                                                    territory: territory
                                                                                                                                                                                                                                                                }
                                                                                                                                                                                                                                                                        };
                                                                                                                                                                                                                                                                            });
                                                                                                                                                                                                                                                                            }

frappe.ui.form.on('Lead', {
    refresh(frm) {
        if (!frm.is_new()) {
            frm.add_custom_button(__('Create Job File'), () => {
                frappe.call({
                    method: 'solar_erp.solar_erp.api.job.create_job_file_from_lead',
                    args: {
                        lead_name: frm.doc.name
                    },
                    callback(r) {
                        if (!r.exc) {
                            frappe.msgprint(__('Job File created successfully'));
                            frm.reload_doc();
                        }
                    }
                });
            });
        }
    }
});
